    (uint112 reserve0, uint112 reserve1, ) = pair.getReserves();

    // Calculate price from reserves (manipulable in single transaction!)
    uint256 price = (reserve1 * 1e18) / reserve0;

    return tokenBalance * price / 1e18;
}

function borrow(uint256 _amount) public {
    uint256 collateralValue = getCollateralValue(msg.sender);
    uint256 maxBorrow = (collateralValue * 75) / 100; // 75% LTV

    require(borrowedAmount[msg.sender] + _amount <= maxBorrow, "Insufficient collateral");

    borrowedAmount[msg.sender] += _amount;
    stablecoin.transfer(msg.sender, _amount);
}
```

