pragma solidity ^0.8.19;

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title SecureLendingProtocol
 * @notice Lending protocol using Chainlink decentralized oracles
 * @dev Demonstrates proper oracle integration with safety checks
 */
contract SecureLendingProtocol is Ownable {
    // Chainlink price feed interface
    AggregatorV3Interface public immutable priceFeed;

    // Price staleness threshold (e.g., 1 hour)
    uint256 public constant MAX_PRICE_AGE = 3600;

    // Price deviation threshold (e.g., 10%)
    uint256 public constant MAX_PRICE_DEVIATION = 10; // 10%

    // Circuit breaker
    bool public paused;

    mapping(address => uint256) public collateralBalances;
    mapping(address => uint256) public borrowBalances;

    event PriceStale(uint256 timestamp, uint256 age);
    event PriceDeviation(uint256 newPrice, uint256 oldPrice, uint256 deviation);
    event CircuitBreakerTriggered(string reason);

    constructor(address _priceFeed) {
        require(_priceFeed != address(0), "Invalid price feed");
        priceFeed = AggregatorV3Interface(_priceFeed);
    }

    /**
     * @notice Get current asset price from Chainlink
     * @dev Includes comprehensive safety checks
     * @return price The current price with 18 decimals
     */
    function getAssetPrice() public view returns (uint256 price) {
        (
            uint80 roundId,
            int256 answer,
            uint256 startedAt,
            uint256 updatedAt,
            uint80 answeredInRound
        ) = priceFeed.latestRoundData();

        // Safety check 1: Ensure price is positive
        require(answer > 0, "Invalid price: negative or zero");

        // Safety check 2: Ensure round is complete
        require(answeredInRound >= roundId, "Stale round");

        // Safety check 3: Ensure price is fresh
        require(updatedAt > 0, "Round not complete");
        uint256 priceAge = block.timestamp - updatedAt;
        require(priceAge <= MAX_PRICE_AGE, "Price too stale");

        // Convert to 18 decimals (Chainlink typically uses 8 decimals)
        uint8 decimals = priceFeed.decimals();
        price = uint256(answer) * 10**(18 - decimals);

        return price;
    }

    /**
     * @notice Get price with additional validation
     * @dev Compares with previous price to detect anomalies
     */
    function getValidatedPrice() public view returns (uint256) {
        require(!paused, "Circuit breaker active");

        uint256 currentPrice = getAssetPrice();

        // Get previous round for comparison
        (
            uint80 currentRoundId,,,,,
        ) = priceFeed.latestRoundData();

        if (currentRoundId > 1) {
            try priceFeed.getRoundData(currentRoundId - 1) returns (
                uint80,
                int256 previousAnswer,
                uint256,
                uint256,
                uint80
            ) {
                if (previousAnswer > 0) {
                    uint8 decimals = priceFeed.decimals();
                    uint256 previousPrice = uint256(previousAnswer) * 10**(18 - decimals);

                    // Calculate deviation
                    uint256 deviation = currentPrice > previousPrice
                        ? ((currentPrice - previousPrice) * 100) / previousPrice
                        : ((previousPrice - currentPrice) * 100) / previousPrice;

                    // Alert if deviation is too high (potential oracle issue)
                    if (deviation > MAX_PRICE_DEVIATION) {
                        emit PriceDeviation(currentPrice, previousPrice, deviation);
                    }
                }
            } catch {
                // Previous round data unavailable, continue with current price
            }
        }

        return currentPrice;
    }

    /**
     * @notice Calculate collateral value using secure oracle
     */
    function calculateCollateralValue(address user) public view returns (uint256) {
        uint256 collateralAmount = collateralBalances[user];
        if (collateralAmount == 0) return 0;

        uint256 price = getValidatedPrice();
        return (collateralAmount * price) / 1e18;
    }

    /**
     * @notice Borrow against collateral
     * @dev Uses Chainlink oracle for safe collateral valuation
     */
    function borrow(uint256 amount) external {
        require(!paused, "Protocol paused");
        require(amount > 0, "Invalid amount");

        uint256 collateralValue = calculateCollateralValue(msg.sender);
        uint256 currentBorrow = borrowBalances[msg.sender];
        uint256 maxBorrow = (collateralValue * 75) / 100; // 75% LTV

        require(currentBorrow + amount <= maxBorrow, "Insufficient collateral");

        borrowBalances[msg.sender] += amount;

        // Transfer borrowed amount
        // ... transfer logic
    }

    /**
     * @notice Emergency circuit breaker
     */
    function triggerCircuitBreaker(string calldata reason) external onlyOwner {
        paused = true;
        emit CircuitBreakerTriggered(reason);
    }

    function unpause() external onlyOwner {
        paused = false;
    }
}

/**
 * @title MultiSourcePriceOracle
 * @notice Advanced implementation using multiple Chainlink feeds
 * @dev Compares multiple price sources for extra security
 */
contract MultiSourcePriceOracle {
    struct PriceFeed {
        AggregatorV3Interface feed;
        uint8 decimals;
        bool active;
    }

    mapping(address => PriceFeed[]) public priceFeeds;
    uint256 public constant MAX_DEVIATION_BETWEEN_FEEDS = 5; // 5%

    /**
     * @notice Add multiple Chainlink feeds for same asset
     * @dev Enables cross-validation between feeds
     */
    function addPriceFeed(address asset, address feedAddress) external {
        AggregatorV3Interface feed = AggregatorV3Interface(feedAddress);
        uint8 decimals = feed.decimals();

        priceFeeds[asset].push(PriceFeed({
            feed: feed,
            decimals: decimals,
            active: true
        }));
    }

    /**
     * @notice Get median price from multiple feeds
     * @dev More resistant to single oracle failure
     */
    function getMedianPrice(address asset) public view returns (uint256) {
        PriceFeed[] memory feeds = priceFeeds[asset];
        require(feeds.length > 0, "No price feeds configured");

        uint256[] memory prices = new uint256[](feeds.length);
        uint256 validPrices = 0;

        // Collect prices from all active feeds
        for (uint256 i = 0; i < feeds.length; i++) {
            if (!feeds[i].active) continue;

            try feeds[i].feed.latestRoundData() returns (
                uint80 roundId,
                int256 answer,
                uint256,
                uint256 updatedAt,
                uint80 answeredInRound
            ) {
                if (answer > 0 && answeredInRound >= roundId && updatedAt > 0) {
                    prices[validPrices] = uint256(answer) * 10**(18 - feeds[i].decimals);
                    validPrices++;
                }
            } catch {
                // Feed failed, skip it
                continue;
            }
        }

        require(validPrices > 0, "No valid prices available");

        // Calculate median (simplified - use quickselect in production)
        uint256 median = _calculateMedian(prices, validPrices);

        // Validate prices are within acceptable deviation
        _validatePriceDeviation(prices, validPrices, median);

        return median;
    }

    function _calculateMedian(uint256[] memory arr, uint256 length) private pure returns (uint256) {
        // Simplified median calculation
        // Production code should use efficient quickselect algorithm
        for (uint256 i = 0; i < length - 1; i++) {
            for (uint256 j = i + 1; j < length; j++) {
                if (arr[i] > arr[j]) {
                    (arr[i], arr[j]) = (arr[j], arr[i]);
                }
            }
        }

        if (length % 2 == 0) {
            return (arr[length / 2 - 1] + arr[length / 2]) / 2;
        } else {
            return arr[length / 2];
        }
    }

    function _validatePriceDeviation(
        uint256[] memory prices,
        uint256 length,
        uint256 median
    ) private pure {
        for (uint256 i = 0; i < length; i++) {
            uint256 deviation = prices[i] > median
                ? ((prices[i] - median) * 100) / median
                : ((median - prices[i]) * 100) / median;

            require(
                deviation <= MAX_DEVIATION_BETWEEN_FEEDS,
                "Price deviation too high between feeds"
            );
        }
    }
}

