pragma solidity ^0.8.19;

import "@uniswap/v3-core/contracts/interfaces/IUniswapV3Pool.sol";
import "@uniswap/v3-periphery/contracts/libraries/OracleLibrary.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title TWAPOracle
 * @notice Secure price oracle using Uniswap V3 TWAP
 * @dev Implements time-weighted average price with configurable windows
 */
contract TWAPOracle is Ownable {
    // Uniswap V3 pool for price observations
    IUniswapV3Pool public immutable pool;

    // Token addresses
    address public immutable token0;
    address public immutable token1;

    // TWAP observation window (e.g., 1800 seconds = 30 minutes)
    uint32 public twapInterval = 1800;

    // Minimum observation window for security
    uint32 public constant MIN_TWAP_INTERVAL = 600; // 10 minutes
    uint32 public constant MAX_TWAP_INTERVAL = 7200; // 2 hours

    event TWAPIntervalUpdated(uint32 oldInterval, uint32 newInterval);
    event PriceQueried(uint256 price, uint32 interval);

    constructor(address _pool) {
        require(_pool != address(0), "Invalid pool");
        pool = IUniswapV3Pool(_pool);
        token0 = pool.token0();
        token1 = pool.token1();
    }

    /**
     * @notice Get TWAP price from Uniswap V3
     * @dev Returns time-weighted average price over specified interval
     * @return price The TWAP price as token1/token0
     */
    function getTWAP() public view returns (uint256 price) {
        // Get TWAP tick from Uniswap V3 Oracle
        (int24 arithmeticMeanTick, ) = OracleLibrary.consult(
            address(pool),
            twapInterval
        );

        // Convert tick to price
        // Uniswap V3 uses ticks for price representation
        // price = 1.0001^tick
        price = OracleLibrary.getQuoteAtTick(
            arithmeticMeanTick,
            uint128(1e18), // Base amount
            token0,
            token1
        );

        emit PriceQueried(price, twapInterval);
        return price;
    }

    /**
     * @notice Get TWAP with custom interval
     * @param _interval Time window in seconds
     */
    function getTWAPWithInterval(uint32 _interval) public view returns (uint256) {
        require(_interval >= MIN_TWAP_INTERVAL, "Interval too short");
        require(_interval <= MAX_TWAP_INTERVAL, "Interval too long");

        (int24 arithmeticMeanTick, ) = OracleLibrary.consult(
            address(pool),
            _interval
        );

        return OracleLibrary.getQuoteAtTick(
            arithmeticMeanTick,
            uint128(1e18),
            token0,
            token1
        );
    }

    /**
     * @notice Update TWAP observation interval
     * @dev Only owner can modify to prevent manipulation
     */
    function setTWAPInterval(uint32 _newInterval) external onlyOwner {
        require(_newInterval >= MIN_TWAP_INTERVAL, "Interval too short");
        require(_newInterval <= MAX_TWAP_INTERVAL, "Interval too long");

        uint32 oldInterval = twapInterval;
        twapInterval = _newInterval;

        emit TWAPIntervalUpdated(oldInterval, _newInterval);
    }

    /**
     * @notice Check if pool has sufficient observation history
     * @dev Ensures TWAP can be calculated accurately
     */
    function hasOracleHistory() public view returns (bool) {
        uint32 oldestObservation = OracleLibrary.getOldestObservationSecondsAgo(address(pool));
        return oldestObservation >= twapInterval;
    }
}

/**
 * @title MultiWindowTWAPOracle
 * @notice Advanced TWAP oracle using multiple time windows
 * @dev Compares short and long TWAPs to detect manipulation
 */
contract MultiWindowTWAPOracle {
    IUniswapV3Pool public immutable pool;

    uint32 public constant SHORT_WINDOW = 600;   // 10 minutes
    uint32 public constant MEDIUM_WINDOW = 1800; // 30 minutes
    uint32 public constant LONG_WINDOW = 3600;   // 1 hour

    // Maximum allowed deviation between windows (5%)
    uint256 public constant MAX_WINDOW_DEVIATION = 5;

    address public immutable token0;
    address public immutable token1;

    event ManipulationDetected(uint256 shortPrice, uint256 longPrice, uint256 deviation);

    constructor(address _pool) {
        pool = IUniswapV3Pool(_pool);
        token0 = pool.token0();
        token1 = pool.token1();
    }

    /**
     * @notice Get validated TWAP price
     * @dev Compares multiple time windows to detect anomalies
     */
    function getValidatedTWAP() public returns (uint256) {
        // Get TWAPs for different windows
        uint256 shortTWAP = _getTWAP(SHORT_WINDOW);
        uint256 mediumTWAP = _getTWAP(MEDIUM_WINDOW);
        uint256 longTWAP = _getTWAP(LONG_WINDOW);

        // Compare short vs long TWAP
        uint256 deviation = shortTWAP > longTWAP
            ? ((shortTWAP - longTWAP) * 100) / longTWAP
            : ((longTWAP - shortTWAP) * 100) / longTWAP;

        // If deviation is too high, possible manipulation attempt
        if (deviation > MAX_WINDOW_DEVIATION) {
            emit ManipulationDetected(shortTWAP, longTWAP, deviation);
            // Return more conservative long-term TWAP
            return longTWAP;
        }

        // Return medium-term TWAP (balanced between freshness and security)
        return mediumTWAP;
    }

    function _getTWAP(uint32 window) private view returns (uint256) {
        (int24 arithmeticMeanTick, ) = OracleLibrary.consult(
            address(pool),
            window
        );

        return OracleLibrary.getQuoteAtTick(
            arithmeticMeanTick,
            uint128(1e18),
            token0,
            token1
        );
    }
}

