        // Compare prices for validation
        uint256 deviation = chainlinkPrice > twapPrice
            ? ((chainlinkPrice - twapPrice) * 100) / twapPrice
            : ((twapPrice - chainlinkPrice) * 100) / chainlinkPrice;

        // If deviation is acceptable, use Chainlink (fresher)
        if (deviation <= MAX_ORACLE_DEVIATION) {
            return chainlinkPrice;
        }

        // Large deviation - possible issue with one oracle
        emit OracleDeviation(chainlinkPrice, twapPrice, deviation);

        // Use more conservative price (lower for collateral)
        return chainlinkPrice < twapPrice ? chainlinkPrice : twapPrice;
    }

    function _getChainlinkPrice() private view returns (uint256 price, bool valid) {
        try chainlinkFeed.latestRoundData() returns (
            uint80 roundId,
            int256 answer,
            uint256,
            uint256 updatedAt,
            uint80 answeredInRound
        ) {
            if (answer > 0 && answeredInRound >= roundId && updatedAt > 0) {
                uint8 decimals = chainlinkFeed.decimals();
                price = uint256(answer) * 10**(18 - decimals);
                valid = true;
            }
        } catch {
            valid = false;
        }
    }

    function _getTWAPPrice() private view returns (uint256) {
        (int24 tick, ) = OracleLibrary.consult(address(uniswapPool), TWAP_WINDOW);
        return OracleLibrary.getQuoteAtTick(tick, uint128(1e18), token0, token1);
    }
}

