pragma solidity ^0.8.19;

import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title FlashLoanDetector
 * @notice Detects and prevents flash loan attacks using multiple heuristics
 * @dev Implements circuit breakers for emergency response
 */
contract FlashLoanDetector is Pausable, AccessControl, ReentrancyGuard {
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    // Flash loan detection thresholds
    uint256 public constant MIN_BALANCE_INCREASE_THRESHOLD = 100 ether;
    uint256 public constant MAX_PRICE_DEVIATION_PER_BLOCK = 5; // 5%
    uint256 public constant MAX_BORROW_PER_BLOCK = 1000000 * 1e6; // 1M USDC

    // Cooldown periods
    mapping(address => uint256) public lastBorrowTime;
    uint256 public constant BORROW_COOLDOWN = 1; // 1 block minimum

    // Transaction monitoring
    mapping(address => uint256) public balanceAtTxStart;
    uint256 public lastBlockPrice;
    uint256 public currentBlockTotalBorrow;
    uint256 public lastProcessedBlock;

    // Emergency pause
    bool public emergencyPaused;
    uint256 public pauseTimestamp;
    uint256 public constant PAUSE_DURATION = 1 hours;

    event FlashLoanDetected(address indexed user, uint256 balanceIncrease, string reason);
    event CircuitBreakerTriggered(string reason, uint256 timestamp);
    event SuspiciousActivity(address indexed user, string metric, uint256 value);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(GUARDIAN_ROLE, msg.sender);
    }

    /**
     * @notice Modifier to detect flash loans
     * @dev Checks if user balance increased significantly during transaction
     */
    modifier flashLoanGuard() {
        // Record balance at transaction start
        uint256 startBalance = address(msg.sender).balance;
        balanceAtTxStart[msg.sender] = startBalance;

        // Execute function
        _;

        // Check balance after function execution
        uint256 endBalance = address(msg.sender).balance;

        if (endBalance > startBalance) {
            uint256 balanceIncrease = endBalance - startBalance;

            // Large balance increase suggests flash loan
            if (balanceIncrease > MIN_BALANCE_INCREASE_THRESHOLD) {
                emit FlashLoanDetected(msg.sender, balanceIncrease, "Large balance increase");
                _triggerCircuitBreaker("Potential flash loan detected");
                revert("Flash loan detected");
            }
        }
    }

    /**
     * @notice Check if transaction exhibits flash loan patterns
     */
    function isFlashLoanSuspicious(address user, uint256 borrowAmount) public returns (bool) {
        // Check 1: Cooldown period
        if (lastBorrowTime[user] > 0) {
            uint256 blocksSinceLastBorrow = block.number - lastBorrowTime[user];
            if (blocksSinceLastBorrow < BORROW_COOLDOWN) {
                emit SuspiciousActivity(user, "Cooldown violation", blocksSinceLastBorrow);
                return true;
            }
        }

        // Check 2: Per-block borrow limit
        if (block.number != lastProcessedBlock) {
            currentBlockTotalBorrow = 0;
            lastProcessedBlock = block.number;
        }

        currentBlockTotalBorrow += borrowAmount;
        if (currentBlockTotalBorrow > MAX_BORROW_PER_BLOCK) {
            emit SuspiciousActivity(user, "Block borrow limit exceeded", currentBlockTotalBorrow);
            return true;
        }

        // Check 3: Known flash loan source addresses
        if (_isKnownFlashLoanProvider(msg.sender)) {
            emit SuspiciousActivity(user, "Flash loan provider detected", 0);
            return true;
        }

        return false;
    }

    /**
     * @notice Price deviation circuit breaker
     * @dev Triggers if price moves too much in single block
     */
    function checkPriceDeviation(uint256 currentPrice) public {
        if (lastBlockPrice > 0) {
            uint256 deviation = currentPrice > lastBlockPrice
                ? ((currentPrice - lastBlockPrice) * 100) / lastBlockPrice
                : ((lastBlockPrice - currentPrice) * 100) / lastBlockPrice;

            if (deviation > MAX_PRICE_DEVIATION_PER_BLOCK) {
                _triggerCircuitBreaker("Excessive price deviation detected");
            }
        }

        lastBlockPrice = currentPrice;
    }

    /**
     * @notice Internal circuit breaker trigger
     */
    function _triggerCircuitBreaker(string memory reason) private {
        if (!emergencyPaused) {
            emergencyPaused = true;
            pauseTimestamp = block.timestamp;
            _pause();
            emit CircuitBreakerTriggered(reason, block.timestamp);
        }
    }

    /**
     * @notice Manual circuit breaker (guardians can trigger)
     */
    function triggerEmergencyPause(string calldata reason) external onlyRole(GUARDIAN_ROLE) {
        _triggerCircuitBreaker(reason);
    }

    /**
     * @notice Unpause after review (admin only)
     */
    function unpause() external onlyRole(ADMIN_ROLE) {
        require(emergencyPaused, "Not paused");
        require(
            block.timestamp >= pauseTimestamp + PAUSE_DURATION,
            "Pause duration not elapsed"
        );

        emergencyPaused = false;
        _unpause();
    }

    /**
     * @notice Check if address is known flash loan provider
     */
    function _isKnownFlashLoanProvider(address addr) private pure returns (bool) {
        // Aave V2 Lending Pool
        if (addr == 0x7d2768dE32b0b80b7a3454c06BdAc94A69DDc7A9) return true;
        // Aave V3 Pool
        if (addr == 0x87870Bca3F3fD6335C3F4ce8392D69350B4fA4E2) return true;
        // dYdX Solo Margin
        if (addr == 0x1E0447b19BB6EcFdAe1e4AE1694b0C3659614e4e) return true;
        // Uniswap V3 (can do flash swaps)
        // Add more known addresses...

        return false;
    }
}

