pragma solidity ^0.8.19;

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";
import "@uniswap/v3-core/contracts/interfaces/IUniswapV3Pool.sol";
import "@uniswap/v3-periphery/contracts/libraries/OracleLibrary.sol";

/**
 * @title MultiOracleAggregator
 * @notice Aggregates prices from multiple oracle sources
 * @dev Uses median calculation for manipulation resistance
 */
contract MultiOracleAggregator {
    struct OracleSource {
        string name;
        address oracle;
        OracleType oracleType;
        uint8 weight;  // Weight for weighted average (0-100)
        bool active;
        uint256 lastUpdateTime;
    }

    enum OracleType {
        CHAINLINK,
        UNISWAP_V3_TWAP,
        BAND_PROTOCOL,
        CUSTOM
    }

    // Oracle sources
    OracleSource[] public oracleSources;

    // Validation parameters
    uint256 public constant MAX_DEVIATION_PERCENT = 5; // 5%
    uint256 public constant MIN_REQUIRED_ORACLES = 2;
    uint32 public constant TWAP_PERIOD = 1800; // 30 minutes

    // Token pair for Uniswap oracles
    address public immutable token0;
    address public immutable token1;

    event OracleAdded(string name, address oracle, OracleType oracleType);
    event OracleRemoved(uint256 index);
    event PriceDeviation(string oracle, uint256 price, uint256 median, uint256 deviation);
    event OracleFailed(string name, string reason);

    constructor(address _token0, address _token1) {
        token0 = _token0;
        token1 = _token1;
    }

    /**
     * @notice Add oracle source
     */
    function addOracle(
        string memory name,
        address oracle,
        OracleType oracleType,
        uint8 weight
    ) external {
        require(oracle != address(0), "Invalid oracle address");
        require(weight <= 100, "Weight must be <= 100");

        oracleSources.push(OracleSource({
            name: name,
            oracle: oracle,
            oracleType: oracleType,
            weight: weight,
            active: true,
            lastUpdateTime: block.timestamp
        }));

        emit OracleAdded(name, oracle, oracleType);
    }

    /**
     * @notice Get aggregated price from all active oracles
     * @return price The median price from all sources
     * @return confidence Confidence score (0-100) based on oracle agreement
     */
    function getAggregatedPrice() external view returns (uint256 price, uint256 confidence) {
        uint256[] memory prices = new uint256[](oracleSources.length);
        uint256 validPriceCount = 0;

        // Query all active oracles
        for (uint256 i = 0; i < oracleSources.length; i++) {
            if (!oracleSources[i].active) continue;

            (uint256 oraclePrice, bool success) = _queryOracle(i);

            if (success && oraclePrice > 0) {
                prices[validPriceCount] = oraclePrice;
                validPriceCount++;
            }
        }

        require(validPriceCount >= MIN_REQUIRED_ORACLES, "Insufficient valid oracles");

        // Calculate median price
        uint256 medianPrice = _calculateMedian(prices, validPriceCount);

        // Calculate confidence based on price deviation
        confidence = _calculateConfidence(prices, validPriceCount, medianPrice);

        return (medianPrice, confidence);
    }

    /**
     * @notice Query individual oracle
     */
    function _queryOracle(uint256 index) private view returns (uint256 price, bool success) {
        OracleSource memory source = oracleSources[index];

        if (source.oracleType == OracleType.CHAINLINK) {
            return _queryChainlink(source.oracle);
        } else if (source.oracleType == OracleType.UNISWAP_V3_TWAP) {
            return _queryUniswapTWAP(source.oracle);
        }

        return (0, false);
    }

    /**
     * @notice Query Chainlink oracle
     */
    function _queryChainlink(address feed) private view returns (uint256 price, bool success) {
        try AggregatorV3Interface(feed).latestRoundData() returns (
            uint80 roundId,
            int256 answer,
            uint256,
            uint256 updatedAt,
            uint80 answeredInRound
        ) {
            if (
                answer > 0 &&
                answeredInRound >= roundId &&
                block.timestamp - updatedAt < 3600
            ) {
                uint8 decimals = AggregatorV3Interface(feed).decimals();
                price = uint256(answer) * 10**(18 - decimals);
                success = true;
            }
        } catch {
            success = false;
        }
    }

    /**
     * @notice Query Uniswap V3 TWAP
     */
    function _queryUniswapTWAP(address pool) private view returns (uint256 price, bool success) {
        try IUniswapV3Pool(pool).observe(_getSecondsAgos()) returns (
            int56[] memory tickCumulatives,
            uint160[] memory
        ) {
            int56 tickCumulativesDelta = tickCumulatives[1] - tickCumulatives[0];
            int24 tick = int24(tickCumulativesDelta / int56(uint56(TWAP_PERIOD)));

            price = OracleLibrary.getQuoteAtTick(
                tick,
                uint128(1e18),
                token0,
                token1
            );
            success = true;
        } catch {
            success = false;
        }
    }

    function _getSecondsAgos() private pure returns (uint32[] memory) {
        uint32[] memory secondsAgos = new uint32[](2);
        secondsAgos[0] = TWAP_PERIOD;
        secondsAgos[1] = 0;
        return secondsAgos;
    }

    /**
     * @notice Calculate median from array of prices
     */
    function _calculateMedian(
        uint256[] memory prices,
        uint256 length
    ) private pure returns (uint256) {
        // Sort prices
        for (uint256 i = 0; i < length - 1; i++) {
            for (uint256 j = i + 1; j < length; j++) {
                if (prices[i] > prices[j]) {
                    (prices[i], prices[j]) = (prices[j], prices[i]);
                }
            }
        }

        // Return median
        if (length % 2 == 0) {
            return (prices[length / 2 - 1] + prices[length / 2]) / 2;
        } else {
            return prices[length / 2];
        }
    }

    /**
     * @notice Calculate confidence score based on price agreement
     * @dev 100 = perfect agreement, lower = higher deviation
     */
    function _calculateConfidence(
        uint256[] memory prices,
        uint256 length,
        uint256 median
    ) private pure returns (uint256) {
        if (length < 2) return 50; // Low confidence with single oracle

        uint256 totalDeviation = 0;

        for (uint256 i = 0; i < length; i++) {
            uint256 deviation = prices[i] > median
                ? ((prices[i] - median) * 100) / median
                : ((median - prices[i]) * 100) / median;

            totalDeviation += deviation;
        }

        uint256 avgDeviation = totalDeviation / length;

        // Convert deviation to confidence score
        if (avgDeviation >= 10) return 0;  // Very low confidence
        if (avgDeviation >= 5) return 50;  // Medium confidence
        if (avgDeviation >= 2) return 75;  // Good confidence
        return 100; // Excellent confidence
    }

    /**
     * @notice Get detailed oracle status
     */
    function getOracleStatus() external view returns (
        string[] memory names,
        uint256[] memory prices,
        bool[] memory statuses
    ) {
        uint256 length = oracleSources.length;
        names = new string[](length);
        prices = new uint256[](length);
        statuses = new bool[](length);

        for (uint256 i = 0; i < length; i++) {
            names[i] = oracleSources[i].name;
            (uint256 price, bool success) = _queryOracle(i);
            prices[i] = price;
            statuses[i] = success;
        }
    }
}

